PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

SELECT ?country ?countryLabel ((?total - ?military) AS ?civilian)
WHERE {
  ?country wdt:P31 wd:Q6256 ;
           wdt:P706 wd:Q23522 ;
           p:P3475 ?totalStmt ;
           p:P2434 ?militaryStmt .
  ?totalStmt ps:P3475 ?total ;
             pq:P607 wd:Q1995 .
  ?militaryStmt ps:P2434 ?military ;
             pq:P607 wd:Q1995 .
  FILTER(isNumeric(?total) && isNumeric(?military))
  FILTER(?total > ?military)
  OPTIONAL {
    ?country rdfs:label ?countryLabel .
    FILTER(LANG(?countryLabel) = "en")
  }
}
ORDER BY DESC(?civilian)

